{"type":"permission_response","request_id":"perm-1773156547894-9rr9wq9","subtype":"success","response":{"updated_input":{"file_path":"/home/ketan/project/kapow/.claude/worktrees/worktree/type-label-fix/web/src/lib/enumLabels.ts","content":"/**
 * Shared code→label mappings for enum search fields.
 * Keyed by search field name (matches registry.go field names).
 */
export const ENUM_LABELS: Record<string, Record<string, string>> = {
  institution_type: {
    '1': 'Public',
    '2': 'Private nonprofit',
    '3': 'Private for-profit',
  },
  highest_degree: {
    '1': 'Certificate',
    '2': "Associate's",
    '3': "Bachelor's",
    '4': "Master's",
    '5': 'Doctorate',
  },
  locale: {
    '11': 'City: Large',
    '12': 'City: Midsize',
    '13': 'City: Small',
    '21': 'Suburb: Large',
    '22': 'Suburb: Midsize',
    '23': 'Suburb: Small',
    '31': 'Town: Fringe',
    '32': 'Town: Distant',
    '33': 'Town: Remote',
    '41': 'Rural: Fringe',
    '42': 'Rural: Distant',
    '43': 'Rural: Remote',
  },
  region: {
    '0': 'U.S. Service Schools',
    '1': 'New England',
    '2': 'Mid East',
    '3': 'Great Lakes',
    '4': 'Plains',
    '5': 'Southeast',
    '6': 'Southwest',
    '7': 'Rocky Mountains',
    '8': 'Far West',
    '9': 'Outlying Areas',
  },
  ncaa_division: {
    '1': 'Division I',
    '2': 'Division II',
    '3': 'Division III',
  },
  koppen_climate: {
    A: 'Tropical',
    B: 'Dry',
    C: 'Temperate',
    D: 'Continental',
    E: 'Polar',
  },
  partisan_direction: {
    D: 'Democrat',
    R: 'Republican',
  },
}

/**
 * Look up a human-readable label for an enum code.
 * Returns null if the field name is not an enum field or the code is unknown.
 * Callers should fall back to the raw value when null is returned.
 */
export function lookupEnumLabel(
  fieldName: string,
  code: string | null | undefined,
): string | null {
  if (code == null) return null
  return ENUM_LABELS[fieldName]?.[code] ?? null
}
