{"type":"permission_response","request_id":"perm-1773156642962-j7gkdmc","subtype":"success","response":{"updated_input":{"file_path":"/home/ketan/project/kapow/.claude/worktrees/worktree/type-label-fix/web/src/lib/enumLabels.test.ts","content":"import { describe, it, expect } from 'vitest'
import { lookupEnumLabel, ENUM_LABELS } from './enumLabels'

describe('ENUM_LABELS', () => {
  it('has entries for all expected field names', () => {
    const expectedFields = [
      'institution_type',
      'highest_degree',
      'locale',
      'region',
      'ncaa_division',
      'koppen_climate',
      'partisan_direction',
    ]
    for (const field of expectedFields) {
      expect(ENUM_LABELS[field]).toBeDefined()
    }
  })
})

describe('lookupEnumLabel', () => {
  it('maps institution_type codes to labels', () => {
    expect(lookupEnumLabel('institution_type', '1')).toBe('Public')
    expect(lookupEnumLabel('institution_type', '2')).toBe('Private nonprofit')
    expect(lookupEnumLabel('institution_type', '3')).toBe('Private for-profit')
  })

  it('maps highest_degree codes to labels', () => {
    expect(lookupEnumLabel('highest_degree', '1')).toBe('Certificate')
    expect(lookupEnumLabel('highest_degree', '2')).toBe("Associate's")
    expect(lookupEnumLabel('highest_degree', '3')).toBe("Bachelor's")
    expect(lookupEnumLabel('highest_degree', '4')).toBe("Master's")
    expect(lookupEnumLabel('highest_degree', '5')).toBe('Doctorate')
  })

  it('maps locale codes to labels', () => {
    expect(lookupEnumLabel('locale', '11')).toBe('City: Large')
    expect(lookupEnumLabel('locale', '12')).toBe('City: Midsize')
    expect(lookupEnumLabel('locale', '43')).toBe('Rural: Remote')
  })

  it('maps region codes to labels', () => {
    expect(lookupEnumLabel('region', '0')).toBe('U.S. Service Schools')
    expect(lookupEnumLabel('region', '1')).toBe('New England')
    expect(lookupEnumLabel('region', '9')).toBe('Outlying Areas')
  })

  it('maps ncaa_division codes to labels', () => {
    expect(lookupEnumLabel('ncaa_division', '1')).toBe('Division I')
    expect(lookupEnumLabel('ncaa_division', '2')).toBe('Division II')
    expect(lookupEnumLabel('ncaa_division', '3')).toBe('Division III')
  })

  it('maps koppen_climate codes to labels', () => {
    expect(lookupEnumLabel('koppen_climate', 'A')).toBe('Tropical')
    expect(lookupEnumLabel('koppen_climate', 'E')).toBe('Polar')
  })

  it('maps partisan_direction codes to labels', () => {
    expect(lookupEnumLabel('partisan_direction', 'D')).toBe('Democrat')
    expect(lookupEnumLabel('partisan_direction', 'R')).toBe('Republican')
  })

  it('returns null for unknown field name', () => {
    expect(lookupEnumLabel('unknown_field', '1')).toBeNull()
  })

  it('returns null for null code', () => {
    expect(lookupEnumLabel('institution_type', null)).toBeNull()
  })

  it('returns null for undefined code', () => {
    expect(lookupEnumLabel('institution_type', undefined)).toBeNull()
  })

  it('returns null for unknown code (caller falls back to raw value)', () => {
    expect(lookupEnumLabel('institution_type', '99')).toBeNull()
    expect(lookupEnumLabel('locale', '99')).toBeNull()
  })
})
"},"permission_updates":[]}}

